import{_ as l,o as i,c as e,Q as a}from"./chunks/framework.6a72df8e.js";const p=JSON.parse('{"title":"访问控制","description":"","frontmatter":{"title":"访问控制","date":"2021-04-16T10:48:42.000Z","tags":["信息安全"],"published":true,"hideInList":false,"feature":null,"isTop":false},"headers":[{"level":2,"title":"访问控制","slug":"访问控制","link":"#访问控制","children":[]},{"level":2,"title":"主体、客体和授权","slug":"主体、客体和授权","link":"#主体、客体和授权","children":[]},{"level":2,"title":"控制访问策略","slug":"控制访问策略","link":"#控制访问策略","children":[]},{"level":2,"title":"决定访问权限","slug":"决定访问权限","link":"#决定访问权限","children":[]},{"level":2,"title":"主体对客体的访问权可以转让吗？","slug":"主体对客体的访问权可以转让吗","link":"#主体对客体的访问权可以转让吗","children":[{"level":3,"title":"1985美国国防部橘皮书","slug":"_1985美国国防部橘皮书","link":"#_1985美国国防部橘皮书","children":[]}]},{"level":2,"title":"访问控制的实现机制","slug":"访问控制的实现机制","link":"#访问控制的实现机制","children":[]}],"relativePath":"src/信息安全/访问控制.md","lastUpdated":1700455155000}'),t={name:"src/信息安全/访问控制.md"},r=a('<p>访问控制！</p><p>还是感谢王继林教授的授课orz</p><h2 id="访问控制" tabindex="-1">访问控制 <a class="header-anchor" href="#访问控制" aria-hidden="true">#</a></h2><ul><li>访问控制对机密性、完整性起直接作用</li><li>对与可用性 <ol><li>谁可以颁发网络可用性的网络管理指令</li><li>谁可以滥用资源</li><li>谁可以获得防止攻击的信息</li></ol></li></ul><h2 id="主体、客体和授权" tabindex="-1">主体、客体和授权 <a class="header-anchor" href="#主体、客体和授权" aria-hidden="true">#</a></h2><ol><li>主体 访问者</li><li>客体 访问目标</li><li>授权 规定对资源可执行的动作（读、写、执行或拒绝访问）</li></ol><h2 id="控制访问策略" tabindex="-1">控制访问策略 <a class="header-anchor" href="#控制访问策略" aria-hidden="true">#</a></h2><ol><li>最小权限原则 该干啥就给啥权限，别给多余的权限</li><li>最小泄露原则 一些事情知道的人越少越好 只给<strong>必须</strong>的资源</li></ol><h2 id="决定访问权限" tabindex="-1">决定访问权限 <a class="header-anchor" href="#决定访问权限" aria-hidden="true">#</a></h2><ul><li>用户分组 <ol><li>特殊用户</li><li>一般用户</li><li>审计用户</li></ol></li><li>资源分类</li><li>资源及使用</li><li>访问规则</li></ul><h2 id="主体对客体的访问权可以转让吗" tabindex="-1">主体对客体的访问权可以转让吗？ <a class="header-anchor" href="#主体对客体的访问权可以转让吗" aria-hidden="true">#</a></h2><ul><li>自主访问控制 能 （例如Windows，Linux，ios，Android）</li><li>强制访问控制 不能 （学生成绩查询系统，军队汇报系统（下级可以向上级通讯，上级不能向下传递，通过安全标签实现信息单向流通））</li><li>基于角色的访问控制 不能</li></ul><h3 id="_1985美国国防部橘皮书" tabindex="-1">1985美国国防部橘皮书 <a class="header-anchor" href="#_1985美国国防部橘皮书" aria-hidden="true">#</a></h3><p>分七类： A B3 B2 B1 C2 C1 D windows是C2级，实现自主访问控制 <strong>超过C2级的操作系统不得向中华人民共和国出售</strong></p><h2 id="访问控制的实现机制" tabindex="-1">访问控制的实现机制 <a class="header-anchor" href="#访问控制的实现机制" aria-hidden="true">#</a></h2><ol><li><strong>访问控制矩阵</strong> 稀疏矩阵 横向与纵向的压缩，使用链表</li><li><strong>CPU指令集的区域划分</strong></li><li><strong>内存控制</strong></li><li><strong>计时器</strong></li></ol>',16),n=[r];function s(d,o,h,c,_,u){return i(),e("div",null,n)}const f=l(t,[["render",s]]);export{p as __pageData,f as default};
